import Brapi from 'brapi';

const client = new Brapi({ apiKey: 'YOUR_TOKEN' });
const quotes = await client.quote.retrieve('PETR4,VALE3', {
  range: '5d',
  interval: '1d',
  fundamental: true,
});
console.log(quotes.results[0].regularMarketPrice);

import Brapi from 'brapi';

const client = new Brapi({ apiKey: 'YOUR_TOKEN' });
const stocks = await client.quote.list({
  search: 'petroleo',
  type: 'stock',
  limit: 10,
  sortBy: 'marketCap',
  sortOrder: 'desc',
});
console.log(stocks.stocks);

import Brapi from 'brapi';

const client = new Brapi({ apiKey: 'YOUR_TOKEN' });
const crypto = await client.crypto.retrieve({
  coin: 'BTC,ETH',
  currency: 'BRL',
});
console.log(crypto.coins);

import Brapi from 'brapi';

const client = new Brapi({ apiKey: 'YOUR_TOKEN' });
const rates = await client.currency.retrieve({
  currency: 'USD-BRL,EUR-BRL',
});
console.log(rates.currency);

import Brapi from 'brapi';

const client = new Brapi({ apiKey: 'YOUR_TOKEN' });
const inflation = await client.inflation.retrieve({
  country: 'brazil',
  historical: true,
  start: '2024-01-01',
});
console.log(inflation.inflation);
